 12→
 13→/** CSS class names for quote reply button */
 14→const CSS_CLASSES = {
 15→  BUTTON: 'gv-quote-btn',
 16→  HIDDEN: 'gv-hidden',
 17→} as const;
 18→
 19→/** Timing constants (in milliseconds) */
 20→const TIMING = {
 21→  /** Delay before performing insertion to wait for UI expansion transitions */
 22→  INSERTION_DELAY_MS: 200,
 23→  /** Delay before retrying focus for editors that need extra time */
 24→  FOCUS_RETRY_DELAY_MS: 50,
 25→  /** Debounce delay for selection change detection */
 26→  SELECTION_DEBOUNCE_MS: 250,
 27→} as const;
 28→
 29→/** UI positioning constants (in pixels) */
 30→const POSITIONING = {
 31→  /** Minimum distance from viewport edge */
 32→  MIN_EDGE_OFFSET_PX: 10,
 33→  /** Gap between button and selection */
 34→  BUTTON_SELECTION_GAP_PX: 16,
 35→} as const;
 36→
 37→/** SVG icon for the quote button */
 38→const QUOTE_ICON = `<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M3 21c3 0 7-1 7-8V5c0-1.25-.756-2.017-2-2H4c-1.25 0-2 .75-2 1.972V11c0 1.25.75 2 2 2 1 0 1 0 1 1v1c0 1-1 2-2 2s-1 .008-1 1.031V20c0 1 0 1 1 1z"></path><path d="M15 21c3 0 7-1 7-8V5c0-1.25-.757-2.017-2-2h-4c-1.25 0-2 .75-2 1.972V11c0 1.25.75 2 2 2 1 0 1 0 1 1v1c0 1-1 2-2 2s-1 .008-1 1.031V20c0 1 0 1 1 1z"></path></svg>`;
