 58→      cursor: pointer;
 59→      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
 60→      font-size: 13px;
 61→      font-weight: 500;
 62→      transition: all 0.2s ease;
 63→      border: 1px solid rgba(255,255,255,0.1);
 64→      transform: translateY(0);
 65→      opacity: 1;
 66→      pointer-events: auto;
 67→    }
 68→    .gv-quote-btn:hover {
 69→      background-color: #2d2d2d;
 70→      transform: translateY(-1px);
