 83→    }
 84→    /* Light mode support */
 85→    @media (prefers-color-scheme: light) {
 86→      .gv-quote-btn {
 87→        background-color: #fff;
 88→        color: #1f1f1f;
 89→        border: 1px solid rgba(0,0,0,0.08);
 90→      }
 91→      .gv-quote-btn:hover {
 92→        background-color: #f5f5f5;
 93→      }
 94→    }
 95→    /* Check for specific theme attributes if Gemini uses them */
 96→    body[data-theme="light"] .gv-quote-btn {
 97→      background-color: #fff;
 98→      color: #1f1f1f;
 99→      border: 1px solid rgba(0,0,0,0.08);
100→    }
101→    body[data-theme="light"] .gv-quote-btn:hover {
