108→// Function to find the chat input
109→function getChatInput(): HTMLElement | null {
110→  // Gemini usually has a rich-textarea
111→  // Try multiple selectors from most specific to generic
112→  const selectors = [
113→    'rich-textarea [contenteditable="true"]',
114→    'div[contenteditable="true"][role="textbox"]',
115→    '.input-area textarea',
116→    'textarea[placeholder*="Ask"]',
117→    'textarea', // Fallback, might be dangerous
118→  ];
119→
120→  for (const selector of selectors) {
121→    // We probably want the one in the main footer/input area, not others (like edit mode)
122→    // Usually the main input is visible and larger.
123→    const els = document.querySelectorAll(selector);
124→    for (const el of Array.from(els)) {
125→      // Check if it's visible
126→      if (el.getBoundingClientRect().height > 0) {
127→        return el as HTMLElement;
128→      }
129→    }
130→  }
131→  return null;
132→}
133→
134→function countLineBreaks(raw: string): number {
135→  return (raw.match(/\n/g) || []).length;
136→}
137→
138→interface SeparatorInsertResult {
139→  inserted: boolean;
140→  insertedBreaks: number;
141→}
142→
143→function getContenteditableQuoteSeparator(): string {
144→  // Firefox + Quill contenteditable tends to render an extra visual break
145→  // for double-newline insertion, so we use a single newline separator there.
146→  return getBrowserName() === 'Firefox' ? '\n' : '\n\n';
147→}
148→
149→function getPlaceholderCandidates(input: HTMLElement): string[] {
150→  const richTextarea = input.closest('rich-textarea');
151→  const candidates = [
152→    input.getAttribute('data-placeholder'),
153→    input.getAttribute('aria-placeholder'),
154→    input.getAttribute('placeholder'),
155→    richTextarea?.getAttribute('data-placeholder'),
156→    richTextarea?.getAttribute('aria-placeholder'),
157→    richTextarea?.getAttribute('placeholder'),
158→  ];
159→
160→  return candidates.filter((value): value is string => Boolean(value)).map((value) => value.trim());
161→}
162→
163→function isChatInputEmpty(input: HTMLElement | HTMLTextAreaElement): boolean {
164→  if (input instanceof HTMLTextAreaElement) {
165→    return input.value.trim().length === 0;
166→  }
167→
168→  const rawContent = input.innerText ?? input.textContent ?? '';
169→  const trimmedContent = rawContent.trim();
170→
171→  // If visible text exists and it's not placeholder text, treat as non-empty even if
172→  // Quill's `ql-blank` class lags behind DOM updates.
173→  if (trimmedContent.length > 0) {
174→    const placeholders = getPlaceholderCandidates(input);
175→    const isPlaceholderText = placeholders.some(
176→      (placeholder) => placeholder.length > 0 && placeholder === trimmedContent,
177→    );
178→    if (!isPlaceholderText) {
179→      return false;
180→    }
181→  }
182→
183→  // Gemini currently uses Quill internals. `ql-blank` is its canonical empty marker.
184→  if (input.classList.contains('ql-blank')) {
185→    return true;
186→  }
187→
188→  return trimmedContent.length === 0;
189→}
190→
191→/**
192→ * Attempts to insert separator text via execCommand and reports whether
193→ * content changed plus how many line breaks were observed as inserted.
194→ */
195→function tryInsertQuoteSeparator(input: HTMLElement, separator: string): SeparatorInsertResult {
196→  const beforeVisible = input.innerText ?? '';
197→  const beforeRaw = input.textContent ?? '';
198→  const beforeVisibleLineBreakCount = countLineBreaks(beforeVisible);
199→  const beforeRawLineBreakCount = countLineBreaks(beforeRaw);
200→  let ok = false;
201→  try {
202→    ok = document.execCommand('insertText', false, separator);
203→  } catch {
204→    ok = false;
205→  }
206→  if (!ok) return { inserted: false, insertedBreaks: 0 };
207→
208→  const afterVisible = input.innerText ?? '';
209→  const afterRaw = input.textContent ?? '';
210→  if (afterVisible === beforeVisible && afterRaw === beforeRaw) {
211→    return { inserted: false, insertedBreaks: 0 };
212→  }
213→
214→  const visibleLineBreakDelta = countLineBreaks(afterVisible) - beforeVisibleLineBreakCount;
215→  const rawLineBreakDelta = countLineBreaks(afterRaw) - beforeRawLineBreakCount;
216→  const insertedBreaks = Math.max(0, visibleLineBreakDelta, rawLineBreakDelta);
217→  return { inserted: true, insertedBreaks };
218→}
219→
220→export function startQuoteReply() {
221→  injectStyles();
222→
223→  let quoteBtn: HTMLElement | null = null;
224→  let currentSelectionRange: Range | null = null;
225→  let isInternalClick = false;
226→  let scrollRafId: number | null = null;
227→  let selectionDebounceTimer: ReturnType<typeof setTimeout> | null = null;
228→
229→  /** Update button position based on current selection range's viewport coordinates. */
230→  function updatePosition() {
231→    if (!quoteBtn || !currentSelectionRange) return;
232→
233→    const rangeRect = currentSelectionRange.getBoundingClientRect();
234→
235→    // Hide when selection is scrolled out of viewport
236→    const isOffScreen = rangeRect.bottom < 0 || rangeRect.top > window.innerHeight;
237→
238→    if (isOffScreen) {
239→      if (!quoteBtn.classList.contains(CSS_CLASSES.HIDDEN)) {
240→        quoteBtn.classList.add(CSS_CLASSES.HIDDEN);
241→      }
242→      return;
243→    }
244→
245→    if (quoteBtn.classList.contains(CSS_CLASSES.HIDDEN)) {
246→      quoteBtn.classList.remove(CSS_CLASSES.HIDDEN);
247→    }
248→
249→    // Ensure the button is visible before measuring to get actual dimensions
250→    const btnRect = quoteBtn.getBoundingClientRect();
251→
252→    // Use getClientRects to get the precise position of the first line.
253→    // This prevents the button from being pushed down by empty space in multi-line selections.
254→    const firstLineRect =
255→      typeof currentSelectionRange.getClientRects === 'function'
256→        ? currentSelectionRange.getClientRects()[0] || rangeRect
257→        : rangeRect;
258→
259→    // position: fixed uses viewport coordinates, no scrollY/X needed
260→    const top = firstLineRect.top - btnRect.height - POSITIONING.BUTTON_SELECTION_GAP_PX;
261→    const left = rangeRect.left + rangeRect.width / 2 - btnRect.width / 2;
262→
263→    // Edge protection: prevent the button from being clipped or overflowing the viewport
264→    const maxLeft = window.innerWidth - btnRect.width - POSITIONING.MIN_EDGE_OFFSET_PX;
265→
266→    quoteBtn.style.top = `${Math.max(POSITIONING.MIN_EDGE_OFFSET_PX, top)}px`;
267→    quoteBtn.style.left = `${Math.min(maxLeft, Math.max(POSITIONING.MIN_EDGE_OFFSET_PX, left))}px`;
268→  }
269→
270→  function onScrollOrResize() {
271→    if (scrollRafId) return;
272→    scrollRafId = requestAnimationFrame(() => {
273→      updatePosition();
274→      scrollRafId = null;
275→    });
276→  }
277→
278→  // Create button
279→  function createButton() {
280→    if (quoteBtn) return;
281→    quoteBtn = document.createElement('div');
282→    quoteBtn.className = `${CSS_CLASSES.BUTTON} ${CSS_CLASSES.HIDDEN}`;
283→    const text = getTranslationSync('quoteReply');
284→
285→    quoteBtn.innerHTML = `${QUOTE_ICON}<span>${text}</span>`;
286→
287→    quoteBtn.addEventListener('mousedown', (e) => {
288→      e.preventDefault();
289→      e.stopPropagation();
290→      isInternalClick = true;
291→      handleQuoteClick();
292→    });
293→
294→    document.body.appendChild(quoteBtn);
295→  }
296→
297→  function handleQuoteClick() {
298→    if (!currentSelectionRange) return;
299→    const selectedText = currentSelectionRange.toString().trim();
300→    if (!selectedText) return;
301→
302→    const input = getChatInput();
303→    if (input) {
304→      expandInputCollapseIfNeeded();
305→
306→      // Format: > selection
307→      // Prepare quote body (without leading/trailing newlines - those are added at insertion time)
308→      const quoteBody = selectedText
309→        .split('\n')
310→        .map((line) => `> ${line}`)
311→        .join('\n');
312→
313→      // Ensure the input is visible
314→      input.scrollIntoView({ behavior: 'smooth', block: 'center' });
315→
316→      // Robust insertion and focus logic
317→      const performInsertion = () => {
318→        // First focus attempt
319→        input.focus();
320→
321→        // Check input state at insertion time to avoid race conditions
322→        // (user might type or another quote might be inserted during the delay)
323→        const isInputEmpty = isChatInputEmpty(input);
324→
325→        // 1. Add a newline at the end (any quote)
326→        // 2. Add a newline at the start if not the first quote
327→        // Example:
328→        // ------------
329→        // |> Quote 1 |
330→        // |New text 1|
331→        // |> Quote 2 |
332→        // |New text 2|
333→        // ------------
334→        const quoteWithTrailingNewline = `${quoteBody}\n`;
335→
336→        if (input instanceof HTMLTextAreaElement) {
337→          // Standard Textarea logic - simplified append
338→          const prefix = isInputEmpty ? '' : '\n\n';
339→          input.value += `${prefix}${quoteWithTrailingNewline}`;
340→          input.selectionStart = input.selectionEnd = input.value.length;
341→          input.dispatchEvent(new Event('input', { bubbles: true }));
342→        } else {
343→          // Contenteditable (Gemini/Quill) logic
344→          const sel = window.getSelection();
345→
346→          // For empty editors, insert from start.
347→          if (sel) {
348→            const range = document.createRange();
349→            range.selectNodeContents(input);
350→            if (isInputEmpty) {
351→              range.collapse(true);
352→            } else {
353→              range.collapse(false); // Move cursor to very end
354→            }
355→            sel.removeAllRanges();
356→            sel.addRange(range);
357→          }
358→
359→          // Try to insert a separator via execCommand in one shot.
360→          // If the command succeeds and mutates content, only the quote body
361→          // (or missing part of it) remains to be inserted.
362→          // If insertion does not mutate content, fall back to prepending separator.
363→          const quoteSeparator = getContenteditableQuoteSeparator();
364→          const requiredSeparatorBreaks = countLineBreaks(quoteSeparator);
365→          let contentToInsert: string;
366→          let forceRangeInsertion = false;
367→          if (!isInputEmpty) {
368→            const separatorResult = tryInsertQuoteSeparator(input, quoteSeparator);
369→            if (separatorResult.inserted) {
370→              const missingBreaks = Math.max(
371→                0,
372→                requiredSeparatorBreaks - separatorResult.insertedBreaks,
373→              );
374→              contentToInsert =
375→                missingBreaks > 0
376→                  ? `${'\n'.repeat(missingBreaks)}${quoteWithTrailingNewline}`
377→                  : quoteWithTrailingNewline;
378→              // Avoid re-running execCommand after partial mutation to prevent duplicate separators.
379→              forceRangeInsertion = missingBreaks > 0;
380→            } else {
381→              contentToInsert = `${quoteSeparator}${quoteWithTrailingNewline}`;
382→            }
383→          } else {
384→            contentToInsert = quoteWithTrailingNewline;
385→          }
386→
387→          // Quill handles text insertion better with native insertText command.
388→          // Fallback to manual Range insertion when command is unavailable.
389→          let inserted = false;
390→          if (!forceRangeInsertion) {
391→            try {
392→              inserted = document.execCommand('insertText', false, contentToInsert);
393→            } catch {
394→              inserted = false;
395→            }
396→          }
397→
398→          if (!inserted) {
399→            const textNode = document.createTextNode(contentToInsert);
400→            if (sel) {
401→              if (forceRangeInsertion) {
402→                const endRange = document.createRange();
403→                endRange.selectNodeContents(input);
404→                endRange.collapse(false);
405→                sel.removeAllRanges();
406→                sel.addRange(endRange);
407→              }
408→            }
409→
410→            if (sel && sel.rangeCount > 0) {
411→              const insertRange = sel.getRangeAt(0);
412→              insertRange.insertNode(textNode);
413→
414→              // Move cursor to after the inserted text
415→              insertRange.setStartAfter(textNode);
416→              insertRange.setEndAfter(textNode);
417→              sel.removeAllRanges();
418→              sel.addRange(insertRange);
419→            } else {
420→              // Fallback: just append to the input
421→              input.appendChild(textNode);
422→            }
423→          }
424→
425→          // Re-force cursor to the end after insertion
426→          const finalRange = document.createRange();
427→          finalRange.selectNodeContents(input);
428→          finalRange.collapse(false);
429→          sel?.removeAllRanges();
430→          sel?.addRange(finalRange);
431→
432→          input.dispatchEvent(new Event('input', { bubbles: true }));
433→        }
434→
435→        // Final focus force
436→        input.focus();
437→        // Some editors need an extra click or focus to show the cursor
438→        setTimeout(() => input.focus(), TIMING.FOCUS_RETRY_DELAY_MS);
439→      };
440→
441→      // Use a slightly longer delay to wait for any expansion transitions
442→      setTimeout(performInsertion, TIMING.INSERTION_DELAY_MS);
443→
444→      // Hide button and clear selection state
445→      hideButton();
446→      currentSelectionRange = null;
447→      window.getSelection()?.removeAllRanges();
448→    } else {
449→      console.warn('[Gemini Voyager] Could not find chat input.');
450→    }
451→  }
452→
453→  function showButton() {
454→    if (!quoteBtn) createButton();
455→    if (!quoteBtn) return;
456→
457→    // updatePosition() manages visibility (HIDDEN class) based on viewport check
458→    updatePosition();
459→
460→    // Add listeners for scroll/resize
461→    window.addEventListener('scroll', onScrollOrResize, { capture: true, passive: true });
462→    window.addEventListener('resize', onScrollOrResize, { passive: true });
463→  }
464→
465→  function hideButton() {
466→    if (quoteBtn) {
467→      quoteBtn.classList.add(CSS_CLASSES.HIDDEN);
468→    }
469→    // Remove listeners
470→    window.removeEventListener('scroll', onScrollOrResize, { capture: true });
471→    window.removeEventListener('resize', onScrollOrResize);
472→    if (scrollRafId) {
473→      cancelAnimationFrame(scrollRafId);
474→      scrollRafId = null;
475→    }
476→  }
477→
478→  function handleSelectionChange() {
479→    // Debounce to let selection settle and avoid redundant updates on rapid key events
480→    if (selectionDebounceTimer) clearTimeout(selectionDebounceTimer);
481→    selectionDebounceTimer = setTimeout(() => {
482→      const selection = window.getSelection();
483→      if (!selection || selection.rangeCount === 0 || selection.isCollapsed) {
484→        hideButton();
485→        currentSelectionRange = null;
486→        return;
487→      }
488→
489→      const text = selection.toString().trim();
490→      if (!text) {
491→        hideButton();
492→        currentSelectionRange = null;
493→        return;
494→      }
495→
496→      // Check if selection is within a message user/model bubble
497→      // We don't want to quote random UI elements
498→      const anchor = selection.anchorNode;
499→      if (!anchor) return;
500→
501→      const element =
502→        anchor.nodeType === Node.TEXT_NODE ? anchor.parentElement : (anchor as HTMLElement);
503→
504→      // Check if selection is inside main content area
505→      // Gemini uses <main> or sometimes specific classes. We want to avoid nav, sidebar, etc.
506→      const mainContent = document.querySelector('main');
507→      if (mainContent && !mainContent.contains(element)) {
508→        hideButton();
509→        return;
510→      }
511→
512→      // Also explicitly check for sidebar classes just in case
513→      if (
514→        element?.closest('nav') ||
515→        element?.closest('[role="navigation"]') ||
516→        element?.closest('.sidebar') ||
517→        element?.closest('.mat-drawer')
518→      ) {
519→        hideButton();
520→        return;
521→      }
522→
523→      // Selectors for valid areas: user-query-container, model-response, conversation-container
524→      // Or just check if it's not the input box itself
525→      if (element?.closest('[contenteditable="true"]')) {
526→        hideButton();
527→        return;
528→      }
529→
530→      // Also check if we are selecting code block content? Might be fine.
531→
532→      const range = selection.getRangeAt(0);
533→      currentSelectionRange = range;
534→      const rect = range.getBoundingClientRect();
535→
536→      // If rect is zero (e.g. invisible), don't show
537→      if (rect.width === 0 && rect.height === 0) return;
538→
539→      showButton();
540→    }, TIMING.SELECTION_DEBOUNCE_MS);
541→  }
542→
543→  function onMouseUp(_: MouseEvent) {
544→    if (isInternalClick) {
545→      isInternalClick = false;
546→      return;
547→    }
548→    handleSelectionChange();
549→  }
550→
551→  // Function to update button text when language changes
552→  function updateButtonText() {
553→    if (quoteBtn) {
554→      const span = quoteBtn.querySelector('span');
555→      if (span) {
556→        span.textContent = getTranslationSync('quoteReply');
557→      }
558→    }
559→  }
560→
561→  // Listen to selection changes via mouseup (often better for "finished" selection)
562→  // selectionchange event fires too often while dragging.
563→  document.addEventListener('mouseup', onMouseUp);
564→
565→  function onKeys(e: KeyboardEvent) {
566→    if (e.key === 'Shift' || e.key.startsWith('Arrow')) {
567→      handleSelectionChange();
568→    }
569→  }
570→
571→  // Also listen to keyup for keyboard selection
572→  document.addEventListener('keyup', onKeys);
573→
574→  // Listen for language changes and update button text
575→  function onStorageChanged(
576→    changes: Record<string, browser.Storage.StorageChange>,
577→    areaName: string,
578→  ) {
579→    if ((areaName === 'sync' || areaName === 'local') && changes[StorageKeys.LANGUAGE]) {
580→      updateButtonText();
581→    }
582→  }
583→  browser.storage.onChanged.addListener(onStorageChanged);
584→
585→  // Cleanup
586→  return () => {
587→    hideButton();
588→    if (selectionDebounceTimer) clearTimeout(selectionDebounceTimer);
589→    document.removeEventListener('mouseup', onMouseUp);
590→    document.removeEventListener('keyup', onKeys);
591→    browser.storage.onChanged.removeListener(onStorageChanged);
592→    if (quoteBtn) quoteBtn.remove();
593→    const style = document.getElementById(STYLE_ID);
594→    if (style) style.remove();
595→  };
596→}
