  1→import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';
  2→
  3→import { getBrowserName } from '@/core/utils/browser';
  4→
  5→import { expandInputCollapseIfNeeded } from '../../inputCollapse/index';
  6→import { startQuoteReply } from '../index';
  7→
  8→vi.mock('../../inputCollapse/index', () => ({
  9→  expandInputCollapseIfNeeded: vi.fn(),
 10→}));
 11→
 12→vi.mock('@/core/utils/browser', () => ({
 13→  getBrowserName: vi.fn(() => 'Chrome/Chromium'),
 14→}));
 15→
 16→function selectSourceText(start = 0, end = 5) {
 17→  const selection = window.getSelection();
 18→  const textNode = document.getElementById('source')?.firstChild;
 19→  if (!(textNode instanceof Text)) {
 20→    throw new Error('Expected a Text node for quote selection.');
 21→  }
 22→
 23→  const range = document.createRange();
 24→  range.setStart(textNode, start);
 25→  range.setEnd(textNode, end);
 26→  selection?.removeAllRanges();
 27→  selection?.addRange(range);
 28→}
 29→
 30→function triggerQuoteReply() {
 31→  selectSourceText();
 32→  document.dispatchEvent(new MouseEvent('mouseup'));
 33→  vi.runAllTimers();
 34→
 35→  const quoteButton = document.querySelector<HTMLElement>('.gv-quote-btn');
 36→  if (!(quoteButton instanceof HTMLElement)) {
 37→    throw new Error('Expected quote button to be present.');
