  1→/**
  2→ * Formula Copy Service
  3→ * Handles copying LaTeX/MathJax formulas from Gemini chat conversations
  4→ * Uses enterprise patterns: Singleton, Service Layer, Event Delegation
  5→ */
  6→import temml from 'temml';
  7→import browser from 'webextension-polyfill';
  8→
  9→import { logger } from '@/core';
 10→import { StorageKeys } from '@/core/types/common';
 11→import type { ILogger } from '@/core/types/common';
 12→
 13→/**
 14→ * Formula copy format options
 15→ */
 16→export type FormulaCopyFormat = 'latex' | 'unicodemath' | 'no-dollar';
 17→
 18→/**
 19→ * Configuration for the formula copy service
 20→ */
 21→export interface FormulaCopyConfig {
 22→  toastDuration?: number;
 23→  toastOffsetY?: number;
 24→  maxTraversalDepth?: number;
 25→  format?: FormulaCopyFormat;
 26→}
 27→
 28→/**
 29→ * Service class for handling formula copy functionality
 30→ * Implements Singleton pattern for single instance management
 31→ */
 32→export class FormulaCopyService {
 33→  private static instance: FormulaCopyService | null = null;
 34→  private static readonly MATHML_NS = 'http://www.w3.org/1998/Math/MathML';
 35→  private readonly logger: ILogger;
 36→  private readonly config: Required<Omit<FormulaCopyConfig, 'format'>>;
 37→  private currentFormat: FormulaCopyFormat = 'latex';
 38→
 39→  // Storage change listener, extracted so it can be removed on destroy
 40→  private readonly handleStorageChange: Parameters<
 41→    typeof browser.storage.onChanged.addListener
 42→  >[0] = (changes, areaName) => {
 43→    if (areaName === 'sync' && changes[StorageKeys.FORMULA_COPY_FORMAT]) {
 44→      const newFormat = changes[StorageKeys.FORMULA_COPY_FORMAT].newValue as FormulaCopyFormat;
 45→      if (newFormat === 'latex' || newFormat === 'unicodemath' || newFormat === 'no-dollar') {
 46→        this.currentFormat = newFormat;
 47→        this.logger.debug('Formula format changed', { format: newFormat });
 48→      }
 49→    }
 50→  };
 51→
 52→  private isInitialized = false;
 53→  private copyToast: HTMLDivElement | null = null;
 54→  private i18nMessages: Record<string, string> = {};
 55→
 56→  private constructor(config: FormulaCopyConfig = {}) {
 57→    this.logger = logger.createChild('FormulaCopy');
 58→    this.config = {
 59→      toastDuration: config.toastDuration ?? 2000,
 60→      toastOffsetY: config.toastOffsetY ?? 40,
 61→      maxTraversalDepth: config.maxTraversalDepth ?? 10,
 62→    };
 63→    this.currentFormat = config.format ?? 'latex';
 64→    this.loadI18nMessages();
 65→    this.loadFormatPreference();
 66→  }
 67→
 68→  /**
 69→   * Get singleton instance
 70→   */
 71→  public static getInstance(config?: FormulaCopyConfig): FormulaCopyService {
 72→    if (!FormulaCopyService.instance) {
 73→      FormulaCopyService.instance = new FormulaCopyService(config);
 74→    }
 75→    return FormulaCopyService.instance;
 76→  }
 77→
 78→  /**
 79→   * Load i18n messages for toast notifications
 80→   */
 81→  private loadI18nMessages(): void {
 82→    try {
 83→      this.i18nMessages = {
 84→        copied: browser.i18n.getMessage('formula_copied') || '✓ Formula copied',
 85→        failed: browser.i18n.getMessage('formula_copy_failed') || '✗ Failed to copy',
 86→      };
 87→    } catch (error) {
 88→      this.logger.warn('Failed to load i18n messages, using defaults', { error });
 89→      this.i18nMessages = {
 90→        copied: '✓ Formula copied',
 91→        failed: '✗ Failed to copy',
 92→      };
 93→    }
 94→  }
 95→
 96→  /**
 97→   * Load format preference from storage
 98→   */
 99→  private async loadFormatPreference(): Promise<void> {
100→    try {
101→      const result = await browser.storage.sync.get(StorageKeys.FORMULA_COPY_FORMAT);
102→      const format = result[StorageKeys.FORMULA_COPY_FORMAT] as FormulaCopyFormat | undefined;
103→      if (format === 'latex' || format === 'unicodemath' || format === 'no-dollar') {
104→        this.currentFormat = format;
105→        this.logger.debug('Loaded formula format preference', { format });
106→      }
107→    } catch (error) {
108→      this.logger.warn('Failed to load format preference, using default', { error });
109→    }
110→
111→    // Listen for format changes
112→    browser.storage.onChanged.addListener(this.handleStorageChange);
113→  }
114→
115→  /**
116→   * Initialize the formula copy feature
117→   */
118→  public initialize(): void {
119→    if (this.isInitialized) {
120→      this.logger.warn('Service already initialized');
121→      return;
122→    }
123→
124→    document.addEventListener('click', this.handleClick, true);
125→    this.isInitialized = true;
126→    this.logger.info('Formula copy service initialized');
127→  }
128→
129→  /**
130→   * Clean up the service (for extension unloading)
131→   */
132→  public destroy(): void {
133→    // Always detach storage change listener
134→    try {
135→      browser.storage.onChanged.removeListener(this.handleStorageChange);
136→    } catch (error) {
137→      this.logger.warn('Failed to remove storage change listener', { error });
138→    }
139→
140→    if (!this.isInitialized) {
141→      this.logger.warn('Service not initialized, cannot destroy');
142→      return;
143→    }
144→
145→    document.removeEventListener('click', this.handleClick, true);
146→    this.removeCopyToast();
147→    this.isInitialized = false;
148→    this.logger.info('Formula copy service destroyed');
149→  }
150→
151→  /**
152→   * Handle click events using event delegation
153→   */
154→  private handleClick = (event: MouseEvent): void => {
155→    const target = event.target as HTMLElement;
156→    const mathElement = this.findMathElement(target);
157→
158→    if (!mathElement) {
159→      return;
160→    }
161→
162→    // Try to extract LaTeX: first from data-math (Gemini), then from annotation (AI Studio)
163→    const latexSource = this.extractLatexSource(mathElement);
164→    if (!latexSource) {
165→      this.logger.warn('Math element found but no LaTeX source available');
166→      return;
167→    }
168→
169→    // Wrap formula with delimiters based on display type
170→    const isDisplayMode = this.isDisplayMode(mathElement);
171→    const { text, html } = this.wrapFormula(latexSource, isDisplayMode);
172→
173→    this.copyFormula(text, html, event.clientX, event.clientY);
174→    event.stopPropagation();
175→  };
176→
177→  /**
178→   * Extract LaTeX source from a math element
179→   * Supports both Gemini (data-math attribute) and AI Studio (annotation element)
180→   */
181→  private extractLatexSource(element: HTMLElement): string | null {
182→    // 1. Try Gemini's data-math attribute
183→    const dataMath = element.getAttribute('data-math');
184→    if (dataMath) {
185→      return dataMath;
186→    }
187→
188→    // 2. Try AI Studio's annotation element with encoding="application/x-tex"
189→    const annotation = element.querySelector('annotation[encoding="application/x-tex"]');
190→    if (annotation?.textContent) {
191→      return annotation.textContent.trim();
192→    }
193→
194→    // 3. Fallback: try any annotation element
195→    const anyAnnotation = element.querySelector('annotation');
196→    if (anyAnnotation?.textContent) {
197→      return anyAnnotation.textContent.trim();
198→    }
199→
200→    return null;
201→  }
202→
203→  /**
204→   * Copy formula to clipboard and show notification
205→   */
206→  private async copyFormula(
207→    text: string,
208→    html: string | undefined,
209→    x: number,
210→    y: number,
211→  ): Promise<void> {
212→    try {
213→      const success = await this.copyToClipboard(text, html);
214→
215→      if (success) {
216→        this.showToast(this.i18nMessages.copied, x, y, true);
217→        this.logger.debug('Formula copied successfully', { length: text.length, hasHtml: !!html });
218→      } else {
219→        this.showToast(this.i18nMessages.failed, x, y, false);
220→        this.logger.error('Failed to copy formula');
221→      }
222→    } catch (error) {
223→      this.showToast(this.i18nMessages.failed, x, y, false);
224→      this.logger.error('Error copying formula', { error });
225→    }
226→  }
227→
228→  /**
229→   * Copy text to clipboard using modern API with fallback
230→   */
231→  private async copyToClipboard(text: string, html?: string): Promise<boolean> {
232→    // Try modern Clipboard API first (supports MIME types)
233→    if (navigator.clipboard?.write) {
234→      const items: Record<string, Blob> = {
235→        'text/plain': new Blob([text], { type: 'text/plain' }),
236→      };
237→
238→      if (html) {
239→        items['text/html'] = new Blob([html], { type: 'text/html' });
240→        if (html.includes(`xmlns:mml="${FormulaCopyService.MATHML_NS}"`)) {
241→          items['application/mathml+xml'] = new Blob([text], { type: 'application/mathml+xml' });
242→        }
243→      }
244→
245→      try {
246→        await navigator.clipboard.write([new ClipboardItem(items)]);
247→        return true;
248→      } catch (error) {
249→        if (this.isMathMLClipboardUnsupported(error)) {
250→          return this.copyToClipboardLegacy(text);
251→        }
252→
253→        this.logger.error('Clipboard API failed, trying fallback', { error });
254→        return this.copyToClipboardLegacy(text);
255→      }
256→    }
257→
258→    // Fallback: If only writeText is available (no MIME support)
259→    if (navigator.clipboard?.writeText && !html) {
260→      try {
261→        await navigator.clipboard.writeText(text);
262→        return true;
263→      } catch (error) {
264→        this.logger.error('Clipboard API failed, trying fallback', { error });
265→        return this.copyToClipboardLegacy(text);
266→      }
267→    }
268→
269→    // Fallback to execCommand for older browsers (text only)
270→    return this.copyToClipboardLegacy(text);
271→  }
272→
273→  /**
274→   * Legacy clipboard copy method using execCommand
275→   */
276→  private copyToClipboardLegacy(text: string): boolean {
277→    try {
278→      const textarea = document.createElement('textarea');
279→      textarea.value = text;
280→      textarea.style.position = 'fixed';
281→      textarea.style.opacity = '0';
282→      textarea.style.pointerEvents = 'none';
283→
284→      document.body.appendChild(textarea);
285→      textarea.select();
286→
287→      const success = document.execCommand('copy');
288→      document.body.removeChild(textarea);
289→
290→      return success;
291→    } catch (error) {
292→      this.logger.error('Legacy clipboard copy failed', { error });
293→      return false;
294→    }
295→  }
296→
297→  private isMathMLClipboardUnsupported(error: unknown): boolean {
298→    const name = this.getErrorName(error);
299→    const nameMatches = name === 'notallowederror' || name === 'notsupportederror';
300→    if (!nameMatches) {
301→      return false;
302→    }
303→
304→    const message = this.getErrorMessage(error);
305→    if (!message) {
306→      return true;
307→    }
308→
309→    const lowerMessage = message.toLowerCase();
310→    return lowerMessage.includes('mathml') || lowerMessage.includes('application/mathml+xml');
311→  }
312→
313→  private getErrorMessage(error: unknown): string | null {
314→    if (error instanceof Error) {
315→      return error.message;
316→    }
317→
318→    return typeof error === 'string' ? error : null;
319→  }
320→
321→  private getErrorName(error: unknown): string | null {
322→    if (error instanceof DOMException) {
323→      return error.name.toLowerCase();
324→    }
325→
326→    if (error instanceof Error) {
327→      return error.name.toLowerCase();
328→    }
329→
330→    return null;
331→  }
332→
333→  /**
334→   * Find the nearest math element in the DOM tree
335→   * Supports both Gemini (data-math attribute) and AI Studio (ms-katex container)
336→   */
337→  private findMathElement(target: HTMLElement): HTMLElement | null {
338→    // 1. Try Gemini's data-math attribute (direct)
339→    const direct = target.closest('[data-math]');
340→    if (direct instanceof HTMLElement) {
341→      return direct;
342→    }
343→
344→    // 2. Try Gemini's .math-inline, .math-block containers
345→    const geminiContainer = target.closest('.math-inline, .math-block');
346→    if (geminiContainer instanceof HTMLElement) {
347→      return this.findDataMathInSubtree(geminiContainer);
348→    }
349→
350→    // 3. Try AI Studio's ms-katex container
351→    const aiStudioContainer = target.closest('ms-katex');
352→    if (aiStudioContainer instanceof HTMLElement) {
353→      return aiStudioContainer;
354→    }
355→
356→    // 4. Try AI Studio: clicked inside .katex element
357→    const katexElement = target.closest('.katex');
358→    if (katexElement instanceof HTMLElement) {
359→      // Find the parent ms-katex container
360→      const parentMsKatex = katexElement.closest('ms-katex');
361→      if (parentMsKatex instanceof HTMLElement) {
362→        return parentMsKatex;
363→      }
364→    }
365→
366→    return null;
367→  }
368→
369→  /**
370→   * Check if element is a math container
371→   */
372→  private isMathContainer(element: HTMLElement): boolean {
373→    return element.classList.contains('math-inline') || element.classList.contains('math-block');
374→  }
375→
376→  /**
377→   * Check if formula is in display mode (block formula)
378→   * Supports both Gemini (.math-block class) and AI Studio (math display="block" attribute)
379→   */
380→  private isDisplayMode(element: HTMLElement): boolean {
381→    // 1. Gemini: check for .math-block container
382→    if (element.closest('.math-block') !== null) {
383→      return true;
384→    }
385→
386→    // 2. AI Studio: check for math element with display="block" attribute
387→    const mathElement = element.querySelector('math[display="block"]');
388→    if (mathElement) {
389→      return true;
390→    }
391→
392→    // 3. AI Studio: check if ms-katex container has block-like styling
393→    // (display formulas are typically block-level in AI Studio)
394→    if (element.tagName.toLowerCase() === 'ms-katex') {
395→      const style = window.getComputedStyle(element);
396→      if (style.display === 'block' || style.display === 'flex') {
397→        return true;
398→      }
399→    }
400→
401→    return false;
402→  }
403→
404→  /**
405→   * Wrap formula with appropriate delimiters based on format
406→   * @param formula - Raw LaTeX formula
407→   * @param isDisplayMode - Whether formula is in display mode
408→   * @returns Object containing text and optional html
409→   */
410→  private wrapFormula(formula: string, isDisplayMode: boolean): { text: string; html?: string } {
411→    if (this.currentFormat === 'unicodemath') {
412→      // Convert to Word-friendly MathML (replaces previous UnicodeMath)
413→      try {
414→        const strippedFormula = this.stripMathDelimiters(formula);
415→        const rawMathML = temml.renderToString(strippedFormula, {
416→          displayMode: isDisplayMode,
417→          xml: true,
418→          annotate: false,
419→          throwOnError: true,
420→          colorIsTextColor: true,
421→          trust: false,
422→        });
423→        const sanitizedMathML = this.stripMathMLAnnotations(rawMathML);
424→        const namespacedMathML = this.ensureMathMLNamespace(sanitizedMathML);
425→        const wordMathML = this.toWordMathML(namespacedMathML);
426→        const htmlWrapped = this.wrapMathMLForWordHtml(wordMathML);
427→
428→        return { text: wordMathML, html: htmlWrapped };
429→      } catch (error) {
430→        this.logger.error('MathML conversion failed', { error });
431→        return { text: formula };
432→      }
433→    }
434→
435→    if (this.currentFormat === 'no-dollar') {
436→      return { text: formula };
437→    }
438→
439→    // Default: LaTeX format with delimiters
440→    const wrapped = isDisplayMode ? `$$${formula}$$` : `$${formula}$`;
441→    return { text: wrapped };
442→  }
443→
444→  private ensureMathMLNamespace(mathML: string): string {
445→    if (mathML.includes('xmlns=')) {
446→      return mathML;
447→    }
448→
449→    return mathML.replace('<math', `<math xmlns="${FormulaCopyService.MATHML_NS}"`);
450→  }
451→
452→  private toWordMathML(mathML: string): string {
453→    const parsed = new DOMParser().parseFromString(mathML, 'application/xml');
454→    if (parsed.getElementsByTagName('parsererror').length > 0) {
455→      return this.stripMathMLAnnotations(mathML);
456→    }
457→
458→    const root = parsed.documentElement;
459→    if (root.localName !== 'math') {
460→      return this.stripMathMLAnnotations(mathML);
461→    }
462→
463→    // Remove annotations (<annotation> and <annotation-xml>)
464→    for (const annotation of Array.from(root.getElementsByTagName('annotation'))) {
465→      annotation.parentNode?.removeChild(annotation);
466→    }
467→    for (const annotationXml of Array.from(root.getElementsByTagName('annotation-xml'))) {
468→      annotationXml.parentNode?.removeChild(annotationXml);
469→    }
470→
471→    // Unwrap <semantics> if present at root
472→    const semantics = Array.from(root.getElementsByTagName('semantics')).find(
473→      (node) => node.parentElement === root,
474→    );
475→    if (semantics) {
476→      const presentation = semantics.firstElementChild;
477→      if (presentation) {
478→        while (root.firstChild) {
479→          root.removeChild(root.firstChild);
480→        }
481→        root.appendChild(presentation);
482→      }
483→    }
484→
485→    this.stripPresentationAttributes(root);
486→
487→    const output = document.implementation.createDocument(
488→      FormulaCopyService.MATHML_NS,
489→      'mml:math',
490→      null,
491→    );
492→    const outputRoot = output.documentElement;
493→
494→    // Copy root attributes (display, etc.), excluding namespace declarations
495→    for (const attr of Array.from(root.attributes)) {
496→      if (attr.name.startsWith('xmlns')) {
497→        continue;
498→      }
499→      outputRoot.setAttribute(attr.name, attr.value);
500→    }
501→
502→    for (const child of Array.from(root.childNodes)) {
503→      outputRoot.appendChild(this.cloneNodeWithMathMLPrefix(output, child));
504→    }
505→
506→    return new XMLSerializer().serializeToString(outputRoot);
507→  }
508→
509→  private cloneNodeWithMathMLPrefix(targetDocument: Document, sourceNode: Node): Node {
510→    if (sourceNode.nodeType === Node.TEXT_NODE) {
511→      return targetDocument.createTextNode(sourceNode.nodeValue ?? '');
512→    }
513→
514→    if (sourceNode.nodeType !== Node.ELEMENT_NODE) {
515→      return targetDocument.importNode(sourceNode, true);
516→    }
517→
518→    const sourceElement = sourceNode as Element;
519→    const namespaceUri = sourceElement.namespaceURI;
520→    const localName = sourceElement.localName;
521→
522→    const isMathMl = namespaceUri === FormulaCopyService.MATHML_NS || namespaceUri === null;
523→    const qualifiedName = isMathMl ? `mml:${localName}` : sourceElement.tagName;
524→    const element = isMathMl
525→      ? targetDocument.createElementNS(FormulaCopyService.MATHML_NS, qualifiedName)
526→      : targetDocument.createElement(qualifiedName);
527→
528→    for (const attr of Array.from(sourceElement.attributes)) {
529→      if (attr.name.startsWith('xmlns')) {
530→        continue;
531→      }
532→      element.setAttribute(attr.name, attr.value);
533→    }
534→
535→    for (const child of Array.from(sourceElement.childNodes)) {
536→      element.appendChild(this.cloneNodeWithMathMLPrefix(targetDocument, child));
537→    }
538→
539→    return element;
540→  }
541→
542→  private wrapMathMLForWordHtml(mathML: string): string {
543→    // Word's HTML importer is sensitive to fragments; include Start/End markers.
544→    return [
545→      `<html xmlns:mml="${FormulaCopyService.MATHML_NS}">`,
546→      '<head><meta charset="utf-8"></head>',
547→      '<body><!--StartFragment-->',
548→      mathML,
549→      '<!--EndFragment--></body></html>',
550→    ].join('');
551→  }
552→
553→  private stripMathMLAnnotations(mathML: string): string {
554→    return mathML
555→      .replace(/<annotation(?:-xml)?[\s\S]*?<\/annotation(?:-xml)?>/g, '')
556→      .replace(/<semantics>\s*([\s\S]*?)\s*<\/semantics>/g, '$1');
557→  }
558→
559→  private stripPresentationAttributes(root: Element): void {
560→    if (root.hasAttribute('class')) {
561→      root.removeAttribute('class');
562→    }
563→    if (root.hasAttribute('style')) {
564→      root.removeAttribute('style');
565→    }
566→
567→    for (const element of Array.from(root.getElementsByTagName('*'))) {
568→      if (element.hasAttribute('class')) {
569→        element.removeAttribute('class');
570→      }
571→      if (element.hasAttribute('style')) {
572→        element.removeAttribute('style');
573→      }
574→    }
575→  }
576→
577→  private stripMathDelimiters(formula: string): string {
578→    const trimmed = formula.trim();
579→
580→    if (trimmed.startsWith('$$') && trimmed.endsWith('$$')) {
581→      return trimmed.slice(2, -2);
582→    }
583→
584→    if (trimmed.startsWith('\\[') && trimmed.endsWith('\\]')) {
585→      return trimmed.slice(2, -2);
586→    }
587→
588→    if (trimmed.startsWith('\\(') && trimmed.endsWith('\\)')) {
589→      return trimmed.slice(2, -2);
590→    }
591→
592→    if (trimmed.startsWith('$') && trimmed.endsWith('$')) {
593→      return trimmed.slice(1, -1);
594→    }
595→
596→    return formula;
597→  }
598→
599→  /**
600→   * Search for data-math attribute in element subtree
601→   */
602→  private findDataMathInSubtree(root: HTMLElement): HTMLElement | null {
603→    const direct = root.querySelector('[data-math]');
604→    return direct instanceof HTMLElement ? direct : null;
605→  }
606→
607→  /**
608→   * Show toast notification
609→   */
610→  private showToast(message: string, x: number, y: number, isSuccess: boolean): void {
611→    if (!this.copyToast) {
612→      this.copyToast = this.createCopyToast();
613→    }
614→
615→    this.copyToast.textContent = message;
616→    this.copyToast.style.left = `${x}px`;
617→    this.copyToast.style.top = `${y - this.config.toastOffsetY}px`;
618→
619→    // Update toast style based on success/failure
620→    if (isSuccess) {
621→      this.copyToast.classList.remove('gv-copy-toast-error');
622→      this.copyToast.classList.add('gv-copy-toast-success');
623→    } else {
624→      this.copyToast.classList.remove('gv-copy-toast-success');
625→      this.copyToast.classList.add('gv-copy-toast-error');
626→    }
627→
628→    this.copyToast.classList.add('gv-copy-toast-show');
629→
630→    setTimeout(() => {
631→      this.copyToast?.classList.remove('gv-copy-toast-show');
632→    }, this.config.toastDuration);
633→  }
634→
635→  /**
636→   * Create toast element
637→   */
638→  private createCopyToast(): HTMLDivElement {
639→    const toast = document.createElement('div');
640→    toast.className = 'gv-copy-toast';
641→    document.body.appendChild(toast);
642→    return toast;
643→  }
644→
645→  /**
646→   * Remove toast element from DOM
647→   */
648→  private removeCopyToast(): void {
649→    if (this.copyToast?.parentElement) {
650→      this.copyToast.parentElement.removeChild(this.copyToast);
651→      this.copyToast = null;
652→    }
653→  }
654→
655→  /**
656→   * Check if service is initialized
657→   */
658→  public isServiceInitialized(): boolean {
659→    return this.isInitialized;
660→  }
661→}
662→
663→// Export singleton instance getter
664→export const getFormulaCopyService = (config?: FormulaCopyConfig) =>
665→  FormulaCopyService.getInstance(config);
