 2→ * KaTeX Configuration Override
 3→ * Suppresses KaTeX strict mode warnings for Unicode text in math mode
 4→ * This allows formulas to contain CJK characters without console warnings
 5→ */
 6→import browser from 'webextension-polyfill';
 7→
 8→import { logger } from '@/core';
 9→
