11→
12→/**
13→ * Override KaTeX strict mode to suppress Unicode warnings
14→ * Must be called early in page load, before KaTeX renders formulas
15→ */
16→export function configureKaTeX(): void {
17→  try {
18→    // Load external script to avoid CSP issues with inline scripts
19→    const script = document.createElement('script');
20→    script.src = browser.runtime.getURL('katex-config.js');
21→    script.type = 'text/javascript';
22→
23→    // Inject into page context (not content script context)
24→    (document.head || document.documentElement).appendChild(script);
25→
26→    katexLogger.info('KaTeX configuration script injected successfully');
27→  } catch (error) {
28→    katexLogger.error('Failed to configure KaTeX', { error });
29→  }
30→}
31→
32→/**
33→ * Initialize KaTeX configuration override
34→ */
35→export function initKaTeXConfig(): void {
36→  configureKaTeX();
37→}
